import{_ as d,o as e,c as r,ag as a}from"./chunks/framework.DmWB24NN.js";const c=JSON.parse('{"title":"CHAPTER 8: EQUIPMENT","description":"","frontmatter":{},"headers":[],"relativePath":"Book I - Core Rules/B01 - Chapter 08_ Equipment.md","filePath":"Book I - Core Rules/B01 - Chapter 08_ Equipment.md"}'),n={name:"Book I - Core Rules/B01 - Chapter 08_ Equipment.md"};function o(s,t,i,l,h,g){return e(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="chapter-8-equipment" tabindex="-1"><strong>CHAPTER 8: EQUIPMENT</strong> <a class="header-anchor" href="#chapter-8-equipment" aria-label="Permalink to &quot;**CHAPTER 8: EQUIPMENT**&quot;">​</a></h1><p>A character without equipment is a collection of ability scores. Equipment is what makes those scores useful — the armor between a character and a sword, the rope between a character and the pit, the coin between a character and the next day&#39;s food.</p><p>This chapter covers what things cost, how much they weigh, and what they do. The prices are guidelines. They reflect the average value under normal supply conditions. The GM should adjust freely for scarcity, politics, and the particular economics of any specific settlement. Haggling down or being gouged up are both possible, especially for unusual items.</p><hr><h2 id="currency" tabindex="-1"><strong>Currency</strong> <a class="header-anchor" href="#currency" aria-label="Permalink to &quot;**Currency**&quot;">​</a></h2><p>Five coins circulate in the Known World. The gold piece is the standard unit for adventurers, and most prices in this chapter are given in gold. The names used here are generic — the GM may rename currencies to fit specific nations or regions.</p><p>All coins weigh 0.5 kg per 50 units regardless of metal.</p><h3 id="table-8-1-exchange-rates" tabindex="-1"><strong>Table 8.1: Exchange Rates</strong> <a class="header-anchor" href="#table-8-1-exchange-rates" aria-label="Permalink to &quot;**Table 8.1: Exchange Rates**&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th>CP</th><th>SP</th><th>EP</th><th>GP</th><th>PP</th></tr></thead><tbody><tr><td>Copper Piece (CP)</td><td>1</td><td>1/10</td><td>1/50</td><td>1/100</td><td>1/500</td></tr><tr><td>Silver Piece (SP)</td><td>10</td><td>1</td><td>1/5</td><td>1/10</td><td>1/50</td></tr><tr><td>Electrum Piece (EP)</td><td>50</td><td>5</td><td>1</td><td>1/5</td><td>1/10</td></tr><tr><td>Gold Piece (GP)</td><td>100</td><td>10</td><td>2</td><td>1</td><td>1/5</td></tr><tr><td>Platinum Piece (PP)</td><td>500</td><td>50</td><td>10</td><td>5</td><td>1</td></tr></tbody></table><p>The copper and silver pieces are common currency — the coins that change hands in markets, taverns, and daily trade. The gold piece circulates among merchants, banks, and adventurers. Electrum and platinum are no longer minted; they survive only in old treasure hoards and private collections. Most merchants will accept them, but not without calculating the exchange rate and probably applying a discount for inconvenience.</p><p>Metal bars also function as portable wealth. A 500-gram gold bar is worth 50 gp. Objects, land deeds, livestock, and rare goods serve as currency in many transactions where large coin transfers would be impractical.</p><hr><h2 id="starting-money" tabindex="-1"><strong>Starting Money</strong> <a class="header-anchor" href="#starting-money" aria-label="Permalink to &quot;**Starting Money**&quot;">​</a></h2><p>Starting funds represent accumulated savings, gifts, windfalls, or anything else that fits the character&#39;s background. These funds are personal — they cannot be shared or pooled during character creation, even if the characters know each other. Multiclass characters use the most favorable row.</p><h3 id="table-8-2-starting-money-by-class" tabindex="-1"><strong>Table 8.2: Starting Money by Class</strong> <a class="header-anchor" href="#table-8-2-starting-money-by-class" aria-label="Permalink to &quot;**Table 8.2: Starting Money by Class**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Class Group</th><th>Starting Funds</th><th>Average</th></tr></thead><tbody><tr><td>Warrior</td><td>5d4 × 10 gp</td><td>100 gp</td></tr><tr><td>Wizard</td><td>(1d4 + 1) × 10 gp</td><td>30 gp</td></tr><tr><td>Rogue</td><td>2d6 × 10 gp</td><td>60 gp</td></tr><tr><td>Priest</td><td>3d6 × 10 gp</td><td>90 gp</td></tr></tbody></table><p><strong>Priests</strong> retain only 1d3 gp after purchasing equipment. The rest is donated to their religious institution or church — either before play begins or immediately upon completion of character creation.</p><hr><h2 id="standard-equipment-lists" tabindex="-1"><strong>Standard Equipment Lists</strong> <a class="header-anchor" href="#standard-equipment-lists" aria-label="Permalink to &quot;**Standard Equipment Lists**&quot;">​</a></h2><p>Prices reflect average availability. Unusual items are annotated with descriptions below their tables.</p><h3 id="table-8-3-containers-and-carrying-capacity" tabindex="-1"><strong>Table 8.3: Containers and Carrying Capacity</strong> <a class="header-anchor" href="#table-8-3-containers-and-carrying-capacity" aria-label="Permalink to &quot;**Table 8.3: Containers and Carrying Capacity**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Item</th><th>Capacity</th><th>Volume</th></tr></thead><tbody><tr><td>Backpack</td><td>25 kg</td><td>3</td></tr><tr><td>Basket, large</td><td>10 kg</td><td>2</td></tr><tr><td>Basket, small</td><td>5 kg</td><td>1</td></tr><tr><td>Belt pouch, large</td><td>4 kg</td><td>6</td></tr><tr><td>Belt pouch, small</td><td>2.5 kg</td><td>4</td></tr><tr><td>Chest, large</td><td>50 kg</td><td>3</td></tr><tr><td>Chest, small</td><td>20 kg</td><td>2</td></tr><tr><td>Sack, extra-large</td><td>40 kg</td><td>4</td></tr><tr><td>Sack, large</td><td>15 kg</td><td>2</td></tr><tr><td>Sack, small</td><td>7.5 kg</td><td>1</td></tr><tr><td>Sack, tiny</td><td>2 kg</td><td>6</td></tr><tr><td>Saddle bags, large</td><td>15 kg</td><td>18</td></tr><tr><td>Saddle bags, small</td><td>10 kg</td><td>1</td></tr></tbody></table><hr><h3 id="table-8-4-clothing" tabindex="-1"><strong>Table 8.4: Clothing</strong> <a class="header-anchor" href="#table-8-4-clothing" aria-label="Permalink to &quot;**Table 8.4: Clothing**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Item</th><th>Cost</th></tr></thead><tbody><tr><td>Belt</td><td>3 sp</td></tr><tr><td>Boots, riding</td><td>3 gp</td></tr><tr><td>Boots, soft</td><td>1 gp</td></tr><tr><td>Breeches</td><td>2 gp</td></tr><tr><td>Cap or hat</td><td>1 sp</td></tr><tr><td>Cloak, good cloth</td><td>8 sp</td></tr><tr><td>Cloak, common fur</td><td>50 gp</td></tr><tr><td>Girdle</td><td>3 gp</td></tr><tr><td>Gloves</td><td>1 gp</td></tr><tr><td>Gown, common</td><td>12 sp</td></tr><tr><td>Hose</td><td>2 gp</td></tr><tr><td>Mittens</td><td>3 sp</td></tr><tr><td>Robe, common</td><td>9 sp</td></tr><tr><td>Robe, embroidered</td><td>20 gp</td></tr><tr><td>Sandals</td><td>5 cp</td></tr><tr><td>Shoes</td><td>1 gp</td></tr><tr><td>Silk jacket</td><td>80 gp</td></tr><tr><td>Surcoat</td><td>6 sp</td></tr><tr><td>Sword scabbard, hanger, baldric</td><td>4 gp</td></tr><tr><td>Tunic</td><td>8 sp</td></tr><tr><td>Vest</td><td>6 sp</td></tr></tbody></table><hr><h3 id="table-8-5-miscellaneous-equipment" tabindex="-1"><strong>Table 8.5: Miscellaneous Equipment</strong> <a class="header-anchor" href="#table-8-5-miscellaneous-equipment" aria-label="Permalink to &quot;**Table 8.5: Miscellaneous Equipment**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Item</th><th>Cost</th><th>Weight</th></tr></thead><tbody><tr><td>Backpack</td><td>2 gp</td><td>1 kg</td></tr><tr><td>Barrel, small</td><td>2 gp</td><td>15 kg</td></tr><tr><td>Bell</td><td>1 gp</td><td>—</td></tr><tr><td>Belt pouch, large</td><td>1 gp</td><td>0.5 kg</td></tr><tr><td>Belt pouch, small</td><td>7 sp</td><td>250 g</td></tr><tr><td>Block and tackle</td><td>5 gp</td><td>2.5 kg</td></tr><tr><td>Bolt case</td><td>1 gp</td><td>0.5 kg</td></tr><tr><td>Bucket</td><td>5 sp</td><td>1.5 kg</td></tr><tr><td>Chain, heavy (per 30 cm)</td><td>4 gp</td><td>1.5 kg</td></tr><tr><td>Chain, light (per 30 cm)</td><td>3 gp</td><td>0.5 kg</td></tr><tr><td>Chest, large</td><td>2 gp</td><td>12.5 kg</td></tr><tr><td>Chest, small</td><td>1 gp</td><td>5 kg</td></tr><tr><td>Candle, tallow</td><td>1 cp</td><td>50 g</td></tr><tr><td>Candle, wax</td><td>1 sp</td><td>50 g</td></tr><tr><td>Chalk</td><td>1 cp</td><td>50 g</td></tr><tr><td>Crampons</td><td>4 gp</td><td>1 kg</td></tr><tr><td>Component pouch</td><td>15 gp</td><td>1 kg</td></tr><tr><td>Fishhook</td><td>1 sp</td><td>—</td></tr><tr><td>Fishing net, 3 m square</td><td>4 gp</td><td>2.5 kg</td></tr><tr><td>Flint and steel</td><td>5 sp</td><td>50 g</td></tr><tr><td>Glass bottle</td><td>10 gp</td><td>50 g</td></tr><tr><td>Grappling hook</td><td>8 sp</td><td>2 kg</td></tr><tr><td>Holy item</td><td>25 gp</td><td>50 g</td></tr><tr><td>Hourglass</td><td>25 gp</td><td>0.5 kg</td></tr><tr><td>Iron pot</td><td>5 sp</td><td>1 kg</td></tr><tr><td>Ladder, 3 m</td><td>5 cp</td><td>10 kg</td></tr><tr><td>Lantern, beacon</td><td>150 gp</td><td>25 kg</td></tr><tr><td>Lantern, bull&#39;s-eye</td><td>12 gp</td><td>1.5 kg</td></tr><tr><td>Lantern, hooded</td><td>7 gp</td><td>1 kg</td></tr><tr><td>Lock, good</td><td>100 gp</td><td>0.5 kg</td></tr><tr><td>Lock, poor</td><td>20 gp</td><td>0.5 kg</td></tr><tr><td>Magnifying glass</td><td>100 gp</td><td>50 g</td></tr><tr><td>Map or scroll case</td><td>8 sp</td><td>250 g</td></tr><tr><td>Merchant&#39;s scale</td><td>2 gp</td><td>0.5 kg</td></tr><tr><td>Mirror, small metal</td><td>10 gp</td><td>50 g</td></tr><tr><td>Musical instrument</td><td>5–100 gp</td><td>250 g</td></tr><tr><td>Oil, Greek fire (per flask)</td><td>10 gp</td><td>1 kg</td></tr><tr><td>Oil, lamp (per flask)</td><td>6 cp</td><td>0.5 kg</td></tr><tr><td>Paper (per sheet)</td><td>2 gp</td><td>—</td></tr><tr><td>Parchment (per sheet)</td><td>1 gp</td><td>—</td></tr><tr><td>Perfume (per vial)</td><td>5 gp</td><td>50 g</td></tr><tr><td>Piton</td><td>3 cp</td><td>250 g</td></tr><tr><td>Quiver</td><td>8 sp</td><td>0.5 kg</td></tr><tr><td>Rope, hemp (per 15 m)</td><td>1 gp</td><td>10 kg</td></tr><tr><td>Rope, silk (per 15 m)</td><td>10 gp</td><td>4 kg</td></tr><tr><td>Sealing wax (per 500 g)</td><td>1 gp</td><td>0.5 kg</td></tr><tr><td>Sewing needle</td><td>5 sp</td><td>—</td></tr><tr><td>Signal whistle</td><td>8 sp</td><td>50 g</td></tr><tr><td>Signet ring or personal seal</td><td>5 gp</td><td>50 g</td></tr><tr><td>Soap (per 500 g)</td><td>5 sp</td><td>0.5 kg</td></tr><tr><td>Spyglass</td><td>1,000 gp</td><td>0.5 kg</td></tr><tr><td>Tent, large</td><td>25 gp</td><td>10 kg</td></tr><tr><td>Tent, pavilion</td><td>100 gp</td><td>25 kg</td></tr><tr><td>Tent, small</td><td>5 gp</td><td>5 kg</td></tr><tr><td>Thieves&#39; picks</td><td>30 gp</td><td>0.5 kg</td></tr><tr><td>Torch</td><td>1 cp</td><td>0.5 kg</td></tr><tr><td>Whetstone</td><td>2 cp</td><td>0.5 kg</td></tr><tr><td>Wineskin</td><td>8 sp</td><td>0.5 kg</td></tr><tr><td>Winter blanket</td><td>5 sp</td><td>1.5 kg</td></tr><tr><td>Writing ink (per vial)</td><td>8 gp</td><td>50 g</td></tr></tbody></table><p><strong>Holy Items.</strong> Religious symbols, blessed water, sacred scripture, and other items sanctified by a faith. Holy items are powerless without priestly blessing through a formal ceremony. Most cannot be purchased outright — they must be requisitioned through the appropriate religious institution. Non-faithful may obtain them only when need is pressing, and the institution reserves the right to decline.</p><p><strong>Lanterns.</strong> Hooded lanterns project light in a 9-metre radius and include a shutter to dim the light. Bull&#39;s-eye lanterns project a 20-metre cone 6 metres wide from a single shutter. Beacon lanterns project a 70-metre cone 30 metres wide and are mounted to buildings, ships, or wagons rather than carried. Hooded and bull&#39;s-eye lanterns burn one flask of oil every 6 hours. Beacon lanterns burn a flask every 2 hours.</p><p><strong>Locks.</strong> Quality determines the difficulty for a Thief attempting to open them.</p><h3 id="table-8-6-lock-quality" tabindex="-1"><strong>Table 8.6: Lock Quality</strong> <a class="header-anchor" href="#table-8-6-lock-quality" aria-label="Permalink to &quot;**Table 8.6: Lock Quality**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Quality</th><th>Modification to Open Locks</th></tr></thead><tbody><tr><td>Wretched</td><td>+30%</td></tr><tr><td>Poor</td><td>+15%</td></tr><tr><td>Good</td><td>0%</td></tr><tr><td>Excellent</td><td>−15%</td></tr><tr><td>Superior</td><td>−30%</td></tr><tr><td>Masterful</td><td>−45%</td></tr></tbody></table><p><strong>Thieves&#39; Picks.</strong> A professional collection of metal rods, picks, a clamp, wedge, hammer, and a small saw. Required to pick locks and remove traps without penalty.</p><hr><h3 id="table-8-7-provisions" tabindex="-1"><strong>Table 8.7: Provisions</strong> <a class="header-anchor" href="#table-8-7-provisions" aria-label="Permalink to &quot;**Table 8.7: Provisions**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Item</th><th>Cost</th></tr></thead><tbody><tr><td>Ale (per gallon)</td><td>2 sp</td></tr><tr><td>Banquet (per person)</td><td>10 gp</td></tr><tr><td>Bread</td><td>5 cp</td></tr><tr><td>Cheese</td><td>4 sp</td></tr><tr><td>Common wine (pitcher)</td><td>2 sp</td></tr><tr><td>Dry rations (per week)</td><td>10 gp</td></tr><tr><td>Eggs or fresh vegetables</td><td>1 cp</td></tr><tr><td>Honey</td><td>5 sp</td></tr><tr><td>Inn lodging, common (per day/week)</td><td>5 sp / 3 gp</td></tr><tr><td>Inn lodging, poor (per day/week)</td><td>5 cp / 2 sp</td></tr><tr><td>Meals, good (per day)</td><td>5 sp</td></tr><tr><td>Meals, common (per day)</td><td>3 sp</td></tr><tr><td>Meals, poor (per day)</td><td>1 sp</td></tr><tr><td>Meat, one meal</td><td>1 sp</td></tr><tr><td>Small beer (per gallon)</td><td>5 cp</td></tr><tr><td>Soup</td><td>5 cp</td></tr></tbody></table><h3 id="table-8-8-living-conditions" tabindex="-1"><strong>Table 8.8: Living Conditions</strong> <a class="header-anchor" href="#table-8-8-living-conditions" aria-label="Permalink to &quot;**Table 8.8: Living Conditions**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Lifestyle</th><th>Cost per Month</th></tr></thead><tbody><tr><td>Squalid</td><td>3 gp</td></tr><tr><td>Poor</td><td>5 gp</td></tr><tr><td>Middle-class</td><td>50 gp per level</td></tr><tr><td>Wealthy</td><td>200 gp per level</td></tr></tbody></table><h3 id="table-8-9-services" tabindex="-1"><strong>Table 8.9: Services</strong> <a class="header-anchor" href="#table-8-9-services" aria-label="Permalink to &quot;**Table 8.9: Services**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Service</th><th>Cost</th></tr></thead><tbody><tr><td>Bath</td><td>3 cp</td></tr><tr><td>Clerk (per letter)</td><td>2 sp</td></tr><tr><td>Doctor, leech, or bleeding</td><td>3 gp</td></tr><tr><td>Guide, city (per day)</td><td>2 sp</td></tr><tr><td>Lantern or torchbearer (per night)</td><td>1 sp</td></tr><tr><td>Laundry (per load)</td><td>1 cp</td></tr><tr><td>Messenger, city (per message)</td><td>1 sp</td></tr><tr><td>Minstrel (per performance)</td><td>3 gp</td></tr><tr><td>Mourner (per funeral)</td><td>2 sp</td></tr><tr><td>Teamster with wagon</td><td>1 sp per 1.5 km</td></tr></tbody></table><hr><h2 id="animals-and-mounts" tabindex="-1"><strong>Animals and Mounts</strong> <a class="header-anchor" href="#animals-and-mounts" aria-label="Permalink to &quot;**Animals and Mounts**&quot;">​</a></h2><p>Animals listed here are domestic and trained — livestock, mounts, and working animals. Dangerous animals that the GM may pit against a party (wolves, bears, hunting cats, warhounds turned hostile) have full entries in Book III.</p><h3 id="table-8-10-animals" tabindex="-1"><strong>Table 8.10: Animals</strong> <a class="header-anchor" href="#table-8-10-animals" aria-label="Permalink to &quot;**Table 8.10: Animals**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Animal</th><th>Cost</th></tr></thead><tbody><tr><td>Boar</td><td>10 gp</td></tr><tr><td>Bull</td><td>20 gp</td></tr><tr><td>Camel</td><td>50 gp</td></tr><tr><td>Cow</td><td>10 gp</td></tr><tr><td>Dog, guard</td><td>25 gp</td></tr><tr><td>Dog, hunting</td><td>17 gp</td></tr><tr><td>Dog, war</td><td>20 gp</td></tr><tr><td>Donkey, mule, or ass</td><td>8 gp</td></tr><tr><td>Elephant, labor</td><td>200 gp</td></tr><tr><td>Elephant, war</td><td>500 gp</td></tr><tr><td>Falcon, trained</td><td>1,000 gp</td></tr><tr><td>Goat</td><td>1 gp</td></tr><tr><td>Horse, draft</td><td>200 gp</td></tr><tr><td>Horse, heavy war</td><td>400 gp</td></tr><tr><td>Horse, light war</td><td>150 gp</td></tr><tr><td>Horse, medium war</td><td>225 gp</td></tr><tr><td>Horse, riding</td><td>75 gp</td></tr><tr><td>Hunting cat (jaguar, panther)</td><td>5,000 gp</td></tr><tr><td>Messenger pigeon</td><td>100 gp</td></tr><tr><td>Ox</td><td>15 gp</td></tr><tr><td>Pig</td><td>3 gp</td></tr><tr><td>Pony</td><td>30 gp</td></tr><tr><td>Ram</td><td>4 gp</td></tr><tr><td>Sheep</td><td>2 gp</td></tr></tbody></table><h3 id="table-8-11-horse-quality-modifiers" tabindex="-1"><strong>Table 8.11: Horse Quality Modifiers</strong> <a class="header-anchor" href="#table-8-11-horse-quality-modifiers" aria-label="Permalink to &quot;**Table 8.11: Horse Quality Modifiers**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Quality</th><th>Movement</th><th>Carrying Capacity</th><th>Cost</th></tr></thead><tbody><tr><td>Nag</td><td>×0.50</td><td>×0.75</td><td>−50%</td></tr><tr><td>Broken-down</td><td>×0.75</td><td>×0.50</td><td>−25%</td></tr><tr><td>Average</td><td>—</td><td>—</td><td>—</td></tr><tr><td>High-spirited</td><td>×1.33</td><td>×1.25</td><td>+33%</td></tr><tr><td>Charger</td><td>×1.50</td><td>×1.33</td><td>+50%</td></tr></tbody></table><p><strong>Horses</strong> require adequate forage or quality grain daily, plus water. Heavy warhorses cannot survive on grazing alone. Saddles and packs must be removed at night, and horses must be tethered to prevent wandering.</p><p><strong>Ponies, donkeys, and mules</strong> are hardier. They survive on grass and forage, don&#39;t need tethering, and can travel through rugged terrain at one less their normal movement rate. They gain +2 on Fortitude saves when double-moving.</p><p><strong>Camels</strong> come in two varieties: Dromedary (sandy desert) and Bactrian (rocky desert). Each reduces movement penalties in their respective terrain by 1. Camels require water every four days and must be tethered.</p><p><strong>Elephants</strong> require dense vegetation for adequate feeding. In sparse terrain they spend most of the day eating and can only move at one-quarter normal rate. They cannot navigate steep declines without a Fortitude save against falling.</p><h3 id="table-8-12-tack-and-harness" tabindex="-1"><strong>Table 8.12: Tack and Harness</strong> <a class="header-anchor" href="#table-8-12-tack-and-harness" aria-label="Permalink to &quot;**Table 8.12: Tack and Harness**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Item</th><th>Cost</th><th>Weight</th></tr></thead><tbody><tr><td>Barding, chain</td><td>500 gp</td><td>35 kg</td></tr><tr><td>Barding, full plate</td><td>2,000 gp</td><td>42.5 kg</td></tr><tr><td>Barding, full scale</td><td>1,000 gp</td><td>37.5 kg</td></tr><tr><td>Barding, half brigandine</td><td>500 gp</td><td>22.5 kg</td></tr><tr><td>Barding, half padded</td><td>100 gp</td><td>12.5 kg</td></tr><tr><td>Barding, leather or padded</td><td>150 gp</td><td>30 kg</td></tr><tr><td>Bit and bridle</td><td>15 sp</td><td>1.5 kg</td></tr><tr><td>Halter</td><td>5 cp</td><td>50 g</td></tr><tr><td>Horseshoes and shoeing</td><td>1 gp</td><td>5 kg</td></tr><tr><td>Saddle, pack</td><td>5 gp</td><td>7.5 kg</td></tr><tr><td>Saddle, riding</td><td>10 gp</td><td>17.5 kg</td></tr><tr><td>Saddle bags, large</td><td>4 gp</td><td>4 kg</td></tr><tr><td>Saddle bags, small</td><td>3 gp</td><td>2.5 kg</td></tr><tr><td>Saddle blanket</td><td>3 sp</td><td>2 kg</td></tr><tr><td>Stabling (per day)</td><td>5 sp</td><td>—</td></tr></tbody></table><p><strong>Barding</strong> provides AC protection for mounts at the cost of movement. Full barding gives the listed AC bonus; half barding provides one less. Barding must be removed for the animal to rest properly. Donning leather barding takes 30 minutes; metal barding takes 60. Removal takes half as long. Flying mounts can wear only leather or lighter. Unusual mounts require custom barding at modified cost and weight.</p><h3 id="table-8-13-transport" tabindex="-1"><strong>Table 8.13: Transport</strong> <a class="header-anchor" href="#table-8-13-transport" aria-label="Permalink to &quot;**Table 8.13: Transport**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Item</th><th>Cost</th></tr></thead><tbody><tr><td>Canoe, small</td><td>30 gp</td></tr><tr><td>Canoe, war</td><td>50 gp</td></tr><tr><td>Carriage, common</td><td>150 gp</td></tr><tr><td>Coach, ornamented</td><td>7,000 gp</td></tr><tr><td>Chariot, riding</td><td>200 gp</td></tr><tr><td>Chariot, war</td><td>500 gp</td></tr><tr><td>Galley, great</td><td>30,000 gp</td></tr><tr><td>Galleon</td><td>50,000 gp</td></tr><tr><td>Longship</td><td>10,000 gp</td></tr><tr><td>Raft or small keelboat</td><td>100 gp</td></tr><tr><td>Wagon or cart</td><td>10 gp</td></tr><tr><td>Wagon wheel</td><td>5 gp</td></tr></tbody></table><p><strong>Carts and wagons.</strong> A hitched mount&#39;s speed is automatically halved. Each additional mount triples the vehicle&#39;s carrying capacity. The vehicle&#39;s weight is not counted against the mount&#39;s carrying limit.</p><hr><h2 id="weapons" tabindex="-1"><strong>Weapons</strong> <a class="header-anchor" href="#weapons" aria-label="Permalink to &quot;**Weapons**&quot;">​</a></h2><p>Characters may own as many weapons as they can carry, subject to encumbrance. The GM should apply reasonable judgment about what a character can realistically have accessible in combat.</p><p><strong>Type</strong> indicates damage kind: Bludgeoning (B), Piercing (P), Slashing (S). Some weapons deal multiple types; a knife deals both P and S. Damage type has no general effect but matters in specific circumstances.</p><p><strong>Combat Speed</strong> determines priority when initiative results tie. Lower speed strikes first in a tie. A weapon&#39;s combat speed is reduced by its enchantment bonus (minimum 0).</p><p><strong>Damage (M/L)</strong> indicates dice rolled against medium-sized targets and large targets respectively.</p><p><strong>Rate of Fire (ROF)</strong> for ranged weapons: two numbers separated by a slash. ROF 1/2 means one attack every two rounds; ROF 2/1 means two attacks per round.</p><p><strong>Range</strong> for ranged weapons: three numbers in metres (short/medium/long). Attacks at medium range suffer −2 to the attack roll; at long range, −5. A weapon cannot be used beyond its maximum range.</p><h3 id="table-8-14-melee-weapons" tabindex="-1"><strong>Table 8.14: Melee Weapons</strong> <a class="header-anchor" href="#table-8-14-melee-weapons" aria-label="Permalink to &quot;**Table 8.14: Melee Weapons**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Weapon</th><th>Cost</th><th>Weight</th><th>Size</th><th>Type</th><th>Speed</th><th>Dmg M</th><th>Dmg L</th></tr></thead><tbody><tr><td>Battle axe</td><td>5 gp</td><td>3.5 kg</td><td>M</td><td>S</td><td>7</td><td>1d8</td><td>1d8</td></tr><tr><td>Club</td><td>—</td><td>1.5 kg</td><td>M</td><td>B</td><td>4</td><td>1d6</td><td>1d3</td></tr><tr><td>Dagger/dirk</td><td>2 gp</td><td>0.5 kg</td><td>S</td><td>P</td><td>2</td><td>1d4</td><td>1d3</td></tr><tr><td>Footman&#39;s flail</td><td>15 gp</td><td>7.5 kg</td><td>M</td><td>B</td><td>7</td><td>1d6+1</td><td>2d4</td></tr><tr><td>Footman&#39;s mace</td><td>8 gp</td><td>5 kg</td><td>M</td><td>B</td><td>7</td><td>1d6+1</td><td>1d6</td></tr><tr><td>Footman&#39;s pick</td><td>8 gp</td><td>3 kg</td><td>M</td><td>P</td><td>7</td><td>1d6+1</td><td>2d4</td></tr><tr><td>Hand axe</td><td>1 gp</td><td>2.5 kg</td><td>M</td><td>S</td><td>4</td><td>1d6</td><td>1d4</td></tr><tr><td>Harpoon</td><td>20 gp</td><td>3 kg</td><td>L</td><td>P</td><td>7</td><td>2d4</td><td>2d6</td></tr><tr><td>Horseman&#39;s flail</td><td>8 gp</td><td>2.5 kg</td><td>M</td><td>B</td><td>6</td><td>1d4+1</td><td>1d4+1</td></tr><tr><td>Horseman&#39;s mace</td><td>5 gp</td><td>3 kg</td><td>M</td><td>B</td><td>6</td><td>1d6</td><td>1d4</td></tr><tr><td>Horseman&#39;s pick</td><td>7 gp</td><td>2 kg</td><td>M</td><td>P</td><td>5</td><td>1d4+1</td><td>1d4</td></tr><tr><td>Javelin</td><td>5 sp</td><td>1 kg</td><td>M</td><td>P</td><td>4</td><td>1d6</td><td>1d6</td></tr><tr><td>Knife</td><td>5 sp</td><td>250 g</td><td>S</td><td>P/S</td><td>2</td><td>1d3</td><td>1d2</td></tr><tr><td>Lance, heavy †</td><td>15 gp</td><td>7.5 kg</td><td>L</td><td>P</td><td>8</td><td>1d8+1</td><td>3d6</td></tr><tr><td>Lance, light †</td><td>6 gp</td><td>2.5 kg</td><td>L</td><td>P</td><td>6</td><td>1d6</td><td>1d8</td></tr><tr><td>Lance, jousting</td><td>20 gp</td><td>10 kg</td><td>L</td><td>P</td><td>10</td><td>1d3−1</td><td>1d2</td></tr><tr><td>Lance, medium †</td><td>10 gp</td><td>5 kg</td><td>L</td><td>P</td><td>7</td><td>1d6+1</td><td>2d6</td></tr><tr><td>Morning star</td><td>10 gp</td><td>6 kg</td><td>M</td><td>B</td><td>7</td><td>2d4</td><td>1d6+1</td></tr><tr><td>Quarterstaff</td><td>—</td><td>2 kg</td><td>L</td><td>B</td><td>4</td><td>1d6</td><td>1d6</td></tr><tr><td>Scourge</td><td>1 gp</td><td>1 kg</td><td>S</td><td>—</td><td>5</td><td>1d4</td><td>1d2</td></tr><tr><td>Sickle</td><td>6 sp</td><td>1.5 kg</td><td>S</td><td>S</td><td>4</td><td>1d4+1</td><td>1d4</td></tr><tr><td>Spear</td><td>8 sp</td><td>2.5 kg</td><td>M</td><td>P</td><td>6</td><td>1d6</td><td>1d8</td></tr><tr><td>Sword, bastard (one-handed)</td><td>25 gp</td><td>5 kg</td><td>M</td><td>S</td><td>6</td><td>1d8</td><td>1d12</td></tr><tr><td>Sword, bastard (two-handed)</td><td>25 gp</td><td>5 kg</td><td>M</td><td>S</td><td>8</td><td>2d4</td><td>2d8</td></tr><tr><td>Sword, broad</td><td>10 gp</td><td>2 kg</td><td>M</td><td>S</td><td>5</td><td>2d4</td><td>1d6+1</td></tr><tr><td>Sword, cutlass</td><td>12 gp</td><td>2 kg</td><td>M</td><td>S</td><td>5</td><td>1d6</td><td>1d8</td></tr><tr><td>Sword, khopesh</td><td>10 gp</td><td>3.5 kg</td><td>M</td><td>S</td><td>9</td><td>2d4</td><td>1d6</td></tr><tr><td>Sword, long</td><td>15 gp</td><td>2 kg</td><td>M</td><td>S</td><td>5</td><td>1d8</td><td>1d12</td></tr><tr><td>Sword, scimitar</td><td>15 gp</td><td>2 kg</td><td>M</td><td>S</td><td>5</td><td>1d8</td><td>1d8</td></tr><tr><td>Sword, short</td><td>10 gp</td><td>1.5 kg</td><td>S</td><td>P</td><td>3</td><td>1d6</td><td>1d8</td></tr><tr><td>Sword, two-handed</td><td>50 gp</td><td>7.5 kg</td><td>L</td><td>S</td><td>10</td><td>1d10</td><td>3d6</td></tr><tr><td>Trident</td><td>15 gp</td><td>2.5 kg</td><td>L</td><td>P</td><td>7</td><td>1d6+1</td><td>3d4</td></tr><tr><td>War hammer</td><td>2 gp</td><td>3 kg</td><td>M</td><td>B</td><td>4</td><td>1d4+1</td><td>1d4</td></tr><tr><td>Whip</td><td>1 sp</td><td>1 kg</td><td>M</td><td>—</td><td>8</td><td>1d2</td><td>1</td></tr></tbody></table><p><strong>Pole Arms</strong> are listed separately below due to their variety.</p><h3 id="table-8-15-pole-arms" tabindex="-1"><strong>Table 8.15: Pole Arms</strong> <a class="header-anchor" href="#table-8-15-pole-arms" aria-label="Permalink to &quot;**Table 8.15: Pole Arms**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Weapon</th><th>Cost</th><th>Weight</th><th>Type</th><th>Speed</th><th>Dmg M</th><th>Dmg L</th></tr></thead><tbody><tr><td>Awl pike</td><td>5 gp</td><td>6 kg</td><td>P</td><td>13</td><td>1d6</td><td>1d12</td></tr><tr><td>Bardiche</td><td>7 gp</td><td>6 kg</td><td>S</td><td>9</td><td>2d4</td><td>2d6</td></tr><tr><td>Bec de corbin</td><td>8 gp</td><td>5 kg</td><td>P/B</td><td>9</td><td>1d8</td><td>1d6</td></tr><tr><td>Bill-guisarme</td><td>7 gp</td><td>7.5 kg</td><td>P/S</td><td>10</td><td>2d4</td><td>1d10</td></tr><tr><td>Fauchard</td><td>5 gp</td><td>3.5 kg</td><td>P/S</td><td>8</td><td>1d6</td><td>1d8</td></tr><tr><td>Fauchard-fork</td><td>8 gp</td><td>4.5 kg</td><td>P/S</td><td>8</td><td>1d8</td><td>1d10</td></tr><tr><td>Glaive ‡</td><td>6 gp</td><td>4 kg</td><td>S</td><td>8</td><td>1d6</td><td>1d10</td></tr><tr><td>Glaive-guisarme ‡</td><td>10 gp</td><td>5 kg</td><td>P/S</td><td>9</td><td>2d4</td><td>2d6</td></tr><tr><td>Guisarme</td><td>5 gp</td><td>4 kg</td><td>S</td><td>8</td><td>2d4</td><td>1d8</td></tr><tr><td>Guisarme-voulge</td><td>8 gp</td><td>7.5 kg</td><td>P/S</td><td>10</td><td>2d4</td><td>2d4</td></tr><tr><td>Halberd</td><td>10 gp</td><td>7.5 kg</td><td>P/S</td><td>9</td><td>1d10</td><td>2d6</td></tr><tr><td>Hook fauchard</td><td>10 gp</td><td>4 kg</td><td>P/S</td><td>9</td><td>1d4</td><td>1d4</td></tr><tr><td>Lucern hammer §</td><td>7 gp</td><td>7.5 kg</td><td>P/B</td><td>9</td><td>2d4</td><td>1d6</td></tr><tr><td>Man-catcher ★</td><td>30 gp</td><td>4 kg</td><td>—</td><td>—</td><td>—</td><td>—</td></tr><tr><td>Military fork ‡</td><td>5 gp</td><td>3.5 kg</td><td>P</td><td>7</td><td>1d8</td><td>2d4</td></tr><tr><td>Partisan §</td><td>10 gp</td><td>4 kg</td><td>P</td><td>9</td><td>1d6</td><td>1d6+1</td></tr><tr><td>Ranseur §</td><td>6 gp</td><td>3.5 kg</td><td>P</td><td>8</td><td>2d4</td><td>2d4</td></tr><tr><td>Spetum §</td><td>5 gp</td><td>3.5 kg</td><td>P</td><td>8</td><td>1d6+1</td><td>3d6</td></tr><tr><td>Voulge</td><td>5 gp</td><td>6 kg</td><td>S</td><td>10</td><td>2d4</td><td>2d4</td></tr></tbody></table><p>‡ <em>Deals double damage against a large or larger creature that charged during the current round.</em> § <em>Deals double damage when set against a charging opponent.</em> † <em>Lance deals double damage when charging on a mount.</em> ★ <em>See Man-catcher description.</em></p><p><strong>Lances.</strong> Each lance is designed for a specific mount size. Using a lance larger than the mount can handle unseats the rider on a successful strike. Medium and heavy lances require breaking off after engagement — at least one round to resituate. Light lances allow continued engagement. On a successful hit, the GM rolls an item saving throw for medium and heavy lances; light lances save only when the modified attack roll equals exactly the target&#39;s AC.</p><p><strong>Man-catcher.</strong> A long pole with spring-loaded arms designed to capture rather than harm. The target&#39;s AC is treated as 10 (modified by Dexterity) when attacked with a man-catcher. Once trapped, the victim loses their Dexterity and shield AC bonus, can only move when the wielder moves, and takes 1d2 damage automatically each round with a 25% chance of being pulled prone. The jaws can be removed with a Bend Bars roll (1d2 additional damage). The victim can pull the pole free with a Strength check; anyone can pick it up and continue using it the following round.</p><p><strong>Spear.</strong> Can function as both melee and ranged weapon. If a thrown spear strikes a Huge or larger creature, or one with Strength 18/00+, the creature may attempt to break it. Intelligent creatures are 75% likely to pull the spear out and hurl it back, 25% likely to break it unless the spear saves vs. crushing blow. Unintelligent creatures have a 25% chance to break it.</p><hr><h3 id="table-8-16-hurled-weapons" tabindex="-1"><strong>Table 8.16: Hurled Weapons</strong> <a class="header-anchor" href="#table-8-16-hurled-weapons" aria-label="Permalink to &quot;**Table 8.16: Hurled Weapons**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Weapon</th><th>ROF</th><th>Range (metres)</th></tr></thead><tbody><tr><td>Club</td><td>1</td><td>9/20/30</td></tr><tr><td>Dagger/dirk</td><td>2/1</td><td>9/20/30</td></tr><tr><td>Dart</td><td>3/1</td><td>9/20/35</td></tr><tr><td>Throwing axe</td><td>1</td><td>9/20/30</td></tr><tr><td>Harpoon</td><td>1</td><td>9/20/30</td></tr><tr><td>Javelin</td><td>1</td><td>20/35/70</td></tr><tr><td>Knife</td><td>2/1</td><td>9/20/30</td></tr><tr><td>Spear</td><td>1</td><td>9/20/30</td></tr></tbody></table><p>Cost, weight, size, type, speed, and damage for hurled weapons are identical to their melee counterparts, except the dart: it has combat speed 2, deals 1d3/1d2 damage (M/L), costs 5 sp, weighs 250 g, and is Small and Piercing. The dart is ineffective as a melee weapon.</p><hr><h3 id="table-8-17-ranged-weapons" tabindex="-1"><strong>Table 8.17: Ranged Weapons</strong> <a class="header-anchor" href="#table-8-17-ranged-weapons" aria-label="Permalink to &quot;**Table 8.17: Ranged Weapons**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Weapon</th><th>Cost</th><th>Weight</th><th>Size</th><th>ROF</th><th>Speed</th><th>Range (metres)</th></tr></thead><tbody><tr><td>Arquebus</td><td>500 gp</td><td>5 kg</td><td>M</td><td>1/3</td><td>15</td><td>45/140/190</td></tr><tr><td>Blowgun</td><td>5 gp</td><td>1 kg</td><td>L</td><td>2/1</td><td>7</td><td>9/20/30</td></tr><tr><td>Bow, composite long</td><td>100 gp</td><td>1.5 kg</td><td>L</td><td>2/1</td><td>7</td><td>55/110/190 (flight); 35/70/150 (sheaf)</td></tr><tr><td>Bow, composite short</td><td>75 gp</td><td>1 kg</td><td>M</td><td>2/1</td><td>6</td><td>45/90/160</td></tr><tr><td>Bow, long</td><td>75 gp</td><td>1.5 kg</td><td>L</td><td>2/1</td><td>8</td><td>65/125/190 (flight); 45/90/150 (sheaf)</td></tr><tr><td>Bow, short</td><td>30 gp</td><td>1 kg</td><td>M</td><td>2/1</td><td>7</td><td>45/90/150</td></tr><tr><td>Crossbow, hand</td><td>300 gp</td><td>1.5 kg</td><td>S</td><td>1</td><td>5</td><td>20/35/55</td></tr><tr><td>Crossbow, heavy</td><td>50 gp</td><td>7 kg</td><td>M</td><td>1/2</td><td>10</td><td>70/145/215</td></tr><tr><td>Crossbow, light</td><td>35 gp</td><td>3.5 kg</td><td>M</td><td>1</td><td>7</td><td>55/110/160</td></tr><tr><td>Sling</td><td>5 cp</td><td>50 g</td><td>S</td><td>1</td><td>6</td><td>45/90/180 (bullet); 35/70/145 (stone)</td></tr><tr><td>Staff sling</td><td>2 sp</td><td>1 kg</td><td>M</td><td>1</td><td>11</td><td>30/110/215 (bullet); 30/90/180 (stone)</td></tr></tbody></table><p><strong>Bows.</strong> A bow adds the character&#39;s Strength and Dexterity modifiers to attack and damage rolls. A standard bow&#39;s maximum pull is Strength +1/+2 (equivalent to 18 Strength). Warriors with exceptional Strength can commission custom composite bows built to their specific rating, increasing the maximum pull — and the price — proportionally.</p><p><strong>Crossbows.</strong> Cannot benefit from Strength modifiers. Dexterity modifiers apply normally.</p><p><strong>Arquebus.</strong> A matchlock firearm. Loading takes 3 rounds; taking damage adds a cumulative round to the loading time. Firing without bracing against a solid surface doubles range penalties (−4 at medium, −10 at long). A roll of 1 or 2 on the attack roll causes a backfire: 1d6 damage to the wielder and the weapon is jammed until cleaned (30 minutes). If the damage die rolls 10, roll again and add the result — this continues until a result other than 10 appears. Gunpowder and shot are rare outside major military forces; the GM determines availability and price for ammunition and supplies.</p><p><strong>Staff sling.</strong> Has a minimum range — it cannot hit targets closer than 30 metres (its short range bracket).</p><h3 id="table-8-18-ammunition" tabindex="-1"><strong>Table 8.18: Ammunition</strong> <a class="header-anchor" href="#table-8-18-ammunition" aria-label="Permalink to &quot;**Table 8.18: Ammunition**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Item</th><th>Cost</th><th>Weight</th><th>Type</th><th>Dmg M</th><th>Dmg L</th></tr></thead><tbody><tr><td>Arrow, flight (12)</td><td>3 sp</td><td>600 g</td><td>P</td><td>1d6</td><td>1d6</td></tr><tr><td>Arrow, sheaf (6)</td><td>3 sp</td><td>300 g</td><td>P</td><td>1d8</td><td>1d8</td></tr><tr><td>Blowgun dart, barbed (10)</td><td>1 gp</td><td>0.5 kg</td><td>P</td><td>1d3</td><td>1d2</td></tr><tr><td>Blowgun dart, needle (10)</td><td>2 sp</td><td>0.5 kg</td><td>P</td><td>1</td><td>1</td></tr><tr><td>Quarrel, hand (10)</td><td>10 gp</td><td>0.5 kg</td><td>P</td><td>1d3</td><td>1d2</td></tr><tr><td>Quarrel, heavy (10)</td><td>2 gp</td><td>0.5 kg</td><td>P</td><td>1d4+1</td><td>1d6+1</td></tr><tr><td>Quarrel, light (10)</td><td>1 gp</td><td>0.5 kg</td><td>P</td><td>1d4</td><td>1d4</td></tr><tr><td>Sling bullet (10)</td><td>1 sp</td><td>2.5 kg</td><td>B</td><td>1d4+1</td><td>1d6+1</td></tr><tr><td>Sling stone</td><td>free</td><td>250 g</td><td>B</td><td>1d4</td><td>1d4</td></tr></tbody></table><p>An arrow that hits is destroyed. An arrow that misses has a 50% chance of being recoverable.</p><hr><h2 id="armor" tabindex="-1"><strong>Armor</strong> <a class="header-anchor" href="#armor" aria-label="Permalink to &quot;**Armor**&quot;">​</a></h2><p>Wearing armor sets a character&#39;s base Armor Class to the listed value. Higher AC is harder to hit. An unarmored character has AC 10.</p><p>If a character&#39;s AC from other sources exceeds what the armor provides, use the higher value — the armor provides no additional benefit in that case, but all other properties (weight, encumbrance, class restrictions) still apply.</p><p>The armor names here are generic. The GM may use specialized historical names where appropriate.</p><h3 id="table-8-19-armor" tabindex="-1"><strong>Table 8.19: Armor</strong> <a class="header-anchor" href="#table-8-19-armor" aria-label="Permalink to &quot;**Table 8.19: Armor**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Armor</th><th>Cost</th><th>Weight</th><th>AC</th></tr></thead><tbody><tr><td>Padded</td><td>4 gp</td><td>5 kg</td><td>12</td></tr><tr><td>Leather</td><td>5 gp</td><td>7.5 kg</td><td>12</td></tr><tr><td>Studded leather</td><td>20 gp</td><td>12.5 kg</td><td>13</td></tr><tr><td>Brigandine</td><td>120 gp</td><td>17.5 kg</td><td>14</td></tr><tr><td>Scale mail</td><td>120 gp</td><td>20 kg</td><td>14</td></tr><tr><td>Chain mail</td><td>75 gp</td><td>20 kg</td><td>15</td></tr><tr><td>Banded mail</td><td>200 gp</td><td>17.5 kg</td><td>16</td></tr><tr><td>Splint mail</td><td>80 gp</td><td>20 kg</td><td>16</td></tr><tr><td>Bronze plate mail</td><td>400 gp</td><td>22.5 kg</td><td>16</td></tr><tr><td>Plate mail</td><td>600 gp</td><td>25 kg</td><td>17</td></tr><tr><td>Field plate</td><td>2,000 gp</td><td>30 kg</td><td>18</td></tr><tr><td>Full plate</td><td>(3d3+1) × 1,000 gp</td><td>35 kg</td><td>19</td></tr></tbody></table><p><strong>The full plate</strong> must be custom-fitted to the wearer. There is a 20% chance a given suit can be refitted for a different wearer. Each suit costs between 4,000 and 10,000 gp, depending on the maker&#39;s quality.</p><h3 id="armor-vulnerability-and-resistance" tabindex="-1"><strong>Armor Vulnerability and Resistance</strong> <a class="header-anchor" href="#armor-vulnerability-and-resistance" aria-label="Permalink to &quot;**Armor Vulnerability and Resistance**&quot;">​</a></h3><p>Armor is not equally effective against all damage types. Rigid metal plates deflect or absorb a sword&#39;s edge but transmit the force of a hammer blow directly into the wearer. Chain resists slashing but gives way to a precisely placed thrust. These interactions are captured by two tags.</p><ul><li><strong>Vulnerable:</strong> The attacker rolls the weapon&#39;s damage dice twice and uses the higher result.</li><li><strong>Resistant:</strong> The attacker rolls the weapon&#39;s damage dice twice and uses the lower result.</li></ul><p>Tags apply only to the damage type listed. All other types deal damage normally. Full rules for applying these tags appear in Chapter 9: Combat.</p><h3 id="table-8-20-armor-vulnerability-and-resistance" tabindex="-1"><strong>Table 8.20: Armor Vulnerability and Resistance</strong> <a class="header-anchor" href="#table-8-20-armor-vulnerability-and-resistance" aria-label="Permalink to &quot;**Table 8.20: Armor Vulnerability and Resistance**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Armor</th><th>Vulnerable</th><th>Resistant</th></tr></thead><tbody><tr><td>Padded</td><td>—</td><td>—</td></tr><tr><td>Leather</td><td>Slashing</td><td>—</td></tr><tr><td>Studded leather</td><td>—</td><td>—</td></tr><tr><td>Brigandine</td><td>—</td><td>—</td></tr><tr><td>Scale mail</td><td>—</td><td>—</td></tr><tr><td>Chain mail</td><td>Piercing</td><td>Slashing</td></tr><tr><td>Banded mail</td><td>—</td><td>—</td></tr><tr><td>Splint mail</td><td>—</td><td>—</td></tr><tr><td>Bronze plate mail</td><td>Bludgeoning</td><td>Slashing</td></tr><tr><td>Plate mail</td><td>Bludgeoning</td><td>Slashing</td></tr><tr><td>Field plate</td><td>Bludgeoning</td><td>Slashing</td></tr><tr><td>Full plate</td><td>Bludgeoning</td><td>Slashing</td></tr></tbody></table><p>Shields and helmets have no vulnerability or resistance tags. Armor worn without its associated helmet type (see Table 8.22) does not gain the helmet&#39;s AC contribution and is not affected by that absence in terms of vulnerability or resistance.</p><h3 id="table-8-21-shields" tabindex="-1"><strong>Table 8.21: Shields</strong> <a class="header-anchor" href="#table-8-21-shields" aria-label="Permalink to &quot;**Table 8.21: Shields**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Shield</th><th>Cost</th><th>Weight</th><th>AC Bonus</th><th>Attacks Covered</th></tr></thead><tbody><tr><td>Buckler</td><td>1 gp</td><td>1.5 kg</td><td>+1</td><td>1 frontal attack (wielder&#39;s choice)</td></tr><tr><td>Small</td><td>3 gp</td><td>2.5 kg</td><td>+1</td><td>2 frontal attacks (wielder&#39;s choice)</td></tr><tr><td>Medium</td><td>7 gp</td><td>5 kg</td><td>+1</td><td>3 frontal attacks</td></tr><tr><td>Body/tower</td><td>10 gp</td><td>7.5 kg</td><td>+1 melee / +2 ranged</td><td>All frontal attacks</td></tr></tbody></table><p>The AC bonus listed is added to a character&#39;s current AC. A <strong>buckler</strong> is strapped to the forearm and permits both hands to be used freely. A <strong>small shield</strong> is gripped by the hand but allows holding small items. A <strong>medium shield</strong> restricts the shield hand entirely. A <strong>body shield</strong> (also called pavise or tower shield) covers against all frontal missile and melee attacks.</p><p>Shields slung across the back provide +1 AC against attacks from behind, except bucklers.</p><h3 id="table-8-22-helmets" tabindex="-1"><strong>Table 8.22: Helmets</strong> <a class="header-anchor" href="#table-8-22-helmets" aria-label="Permalink to &quot;**Table 8.22: Helmets**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Helmet</th><th>Cost</th><th>Weight</th><th>Armor Match</th><th>Penalty Without</th></tr></thead><tbody><tr><td>Cap</td><td>4 gp</td><td>1 kg</td><td>Light (padded through studded)</td><td>−1 AC</td></tr><tr><td>Coif</td><td>8 gp</td><td>2.5 kg</td><td>Medium (chain, scale)</td><td>−1 AC</td></tr><tr><td>Open-face</td><td>15 gp</td><td>2.5 kg</td><td>Medium or heavy</td><td>−1 AC</td></tr><tr><td>Basinet/closed-face</td><td>20 gp</td><td>5 kg</td><td>Heavy (banded or better)</td><td>−1 AC</td></tr><tr><td>Great helm</td><td>30 gp</td><td>5 kg</td><td>Heavy (banded or better)</td><td>−1 AC</td></tr></tbody></table><p>Characters wearing armor without its associated helmet type suffer −1 to their AC. Mismatched helmets with armor are functional but may impose Charisma penalties for appearing unprofessional, at the GM&#39;s discretion.</p><h3 id="armor-for-non-standard-sizes" tabindex="-1"><strong>Armor for Non-Standard Sizes</strong> <a class="header-anchor" href="#armor-for-non-standard-sizes" aria-label="Permalink to &quot;**Armor for Non-Standard Sizes**&quot;">​</a></h3><p>Humanoids significantly larger or smaller than man-sized must have armor custom-fitted. Cost and weight scale by size category.</p><table tabindex="0"><thead><tr><th>Size</th><th>Cost</th><th>Weight</th></tr></thead><tbody><tr><td>Small (halfling-sized)</td><td>×0.75</td><td>×0.75</td></tr><tr><td>Large (ogre-sized)</td><td>×2</td><td>×2</td></tr><tr><td>Huge (giant-sized)</td><td>×4</td><td>×4</td></tr><tr><td>Gigantic (titan-sized)</td><td>×8</td><td>×8</td></tr></tbody></table><p>Badaki and Ûrgon characters require custom armor by this table. Val&#39;arian and Duardeen characters use standard sizing.</p><hr><h2 id="donning-and-removing-armor" tabindex="-1"><strong>Donning and Removing Armor</strong> <a class="header-anchor" href="#donning-and-removing-armor" aria-label="Permalink to &quot;**Donning and Removing Armor**&quot;">​</a></h2><p>Armor takes time to put on properly. Donning hastily or removing quickly are both possible with trade-offs.</p><table tabindex="0"><thead><tr><th>Armor Type</th><th>With Assistance</th><th>Without Assistance</th></tr></thead><tbody><tr><td>Brigandine, leather, padded, studded</td><td>1 round</td><td>2 rounds</td></tr><tr><td>Banded, chain, scale, splint</td><td>2 rounds</td><td>4 rounds</td></tr><tr><td>Plate variants</td><td>1d6+4 rounds</td><td>Triple time</td></tr></tbody></table><p><strong>Hasty donning.</strong> Non-plate armor donned hastily takes 1 round but reduces the AC bonus by 1 (minimum AC 12 — no worse than leather). Plate armor hastily donned improves AC by 1 per round of effort — each round spent adds 1 AC above base 10 until fully donned.</p><p><strong>Removing armor.</strong> Non-plate takes 1 round. Plate takes 1d4+1 rounds. Plate can be cut off in half the time (round up) by cutting straps, but the armor is useless until repaired.</p><hr><h2 id="encumbrance" tabindex="-1"><strong>Encumbrance</strong> <a class="header-anchor" href="#encumbrance" aria-label="Permalink to &quot;**Encumbrance**&quot;">​</a></h2><p>Encumbrance measures the effect of carried weight on movement and combat effectiveness. There are two distinct limits to track: <strong>maximum weight</strong> and <strong>maximum carrying capacity</strong>.</p><p><strong>Maximum weight</strong> is derived from Strength (Table 1.1). Exceeding it imposes movement penalties.</p><p><strong>Maximum carrying capacity</strong> is determined by the character&#39;s size and the physical bulk of their possessions — the number and size of objects, not their weight. A character may hit their weight limit before their capacity limit, or vice versa. Additional attack and AC penalties only apply when both limits are reached simultaneously.</p><h3 id="encumbrance-stages-for-man-sized-bipeds" tabindex="-1"><strong>Encumbrance Stages for Man-Sized Bipeds</strong> <a class="header-anchor" href="#encumbrance-stages-for-man-sized-bipeds" aria-label="Permalink to &quot;**Encumbrance Stages for Man-Sized Bipeds**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Stage</th><th>Attack Modifier</th><th>AC Modifier</th></tr></thead><tbody><tr><td>Non-encumbered</td><td>—</td><td>—</td></tr><tr><td>Lightly encumbered</td><td>—</td><td>—</td></tr><tr><td>Moderately encumbered</td><td>−1 (at max capacity)</td><td>—</td></tr><tr><td>Heavily encumbered</td><td>−2 (at max capacity)</td><td>−1 (at max capacity)</td></tr><tr><td>Severely encumbered</td><td>−4 (at max capacity)</td><td>−3 (at max capacity)</td></tr><tr><td>Overwhelmingly encumbered</td><td>−4 (at max capacity)</td><td>−3 (at max capacity)</td></tr></tbody></table><p><em>At max capacity</em> means both weight and bulk limits are reached. Either limit alone imposes only the movement penalty.</p><h3 id="table-8-23-encumbrance-by-strength-man-sized-bipeds" tabindex="-1"><strong>Table 8.23: Encumbrance by Strength (Man-Sized Bipeds)</strong> <a class="header-anchor" href="#table-8-23-encumbrance-by-strength-man-sized-bipeds" aria-label="Permalink to &quot;**Table 8.23: Encumbrance by Strength (Man-Sized Bipeds)**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Strength</th><th>Non-Enc</th><th>Light</th><th>Moderate</th><th>Heavy</th><th>Severe</th><th>Max</th></tr></thead><tbody><tr><td>3</td><td>2.5</td><td>5</td><td>7.5</td><td>10</td><td>12.5</td><td>15</td></tr><tr><td>4</td><td>5</td><td>10</td><td>15</td><td>20</td><td>25</td><td>30</td></tr><tr><td>5</td><td>7.5</td><td>15</td><td>22.5</td><td>27.5</td><td>32.5</td><td>37.5</td></tr><tr><td>6</td><td>10</td><td>20</td><td>27.5</td><td>32.5</td><td>37.5</td><td>45</td></tr><tr><td>7</td><td>10</td><td>20</td><td>27.5</td><td>32.5</td><td>37.5</td><td>45</td></tr><tr><td>8</td><td>17.5</td><td>29</td><td>38</td><td>44</td><td>50</td><td>57.5</td></tr><tr><td>9</td><td>17.5</td><td>29</td><td>38</td><td>44</td><td>50</td><td>57.5</td></tr><tr><td>10–11</td><td>20</td><td>32</td><td>41</td><td>47</td><td>54</td><td>65</td></tr><tr><td>12–13</td><td>22.5</td><td>35.5</td><td>44</td><td>50</td><td>57.5</td><td>75</td></tr><tr><td>14–15</td><td>27.5</td><td>41.5</td><td>51.5</td><td>59</td><td>67.5</td><td>85</td></tr><tr><td>16</td><td>35</td><td>51</td><td>62</td><td>71</td><td>82.5</td><td>97.5</td></tr><tr><td>17</td><td>42.5</td><td>61</td><td>74.5</td><td>87.5</td><td>100</td><td>120</td></tr><tr><td>18</td><td>55</td><td>74</td><td>86.5</td><td>100</td><td>112.5</td><td>135</td></tr><tr><td>18/01–50</td><td>67.5</td><td>87.5</td><td>100</td><td>112.5</td><td>127.5</td><td>150</td></tr><tr><td>18/51–75</td><td>80</td><td>100</td><td>112.5</td><td>125</td><td>140</td><td>165</td></tr><tr><td>18/76–90</td><td>92.5</td><td>112.5</td><td>125</td><td>138</td><td>152.5</td><td>180</td></tr><tr><td>18/91–99</td><td>117.5</td><td>135</td><td>147.5</td><td>160</td><td>177.5</td><td>200</td></tr><tr><td>18/00</td><td>167.5</td><td>187.5</td><td>200</td><td>215</td><td>232.5</td><td>255</td></tr><tr><td>19</td><td>242.5</td><td>262.5</td><td>274</td><td>290</td><td>307.5</td><td>330</td></tr><tr><td>20</td><td>267.5</td><td>287.5</td><td>300</td><td>317.5</td><td>335</td><td>360</td></tr><tr><td>21</td><td>317.5</td><td>340</td><td>354</td><td>374</td><td>392.5</td><td>415</td></tr><tr><td>22</td><td>392.5</td><td>417.5</td><td>432.5</td><td>452.5</td><td>472.5</td><td>500</td></tr><tr><td>23</td><td>467.5</td><td>492.5</td><td>509</td><td>529</td><td>549</td><td>575</td></tr><tr><td>24</td><td>617.5</td><td>645</td><td>662.5</td><td>685</td><td>710</td><td>740</td></tr><tr><td>25</td><td>767.5</td><td>795</td><td>812.5</td><td>835</td><td>860</td><td>895</td></tr></tbody></table><p><em>All weights in kilograms.</em></p><h3 id="movement-under-encumbrance" tabindex="-1"><strong>Movement Under Encumbrance</strong> <a class="header-anchor" href="#movement-under-encumbrance" aria-label="Permalink to &quot;**Movement Under Encumbrance**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Encumbrance</th><th>MV 12</th><th>MV 9</th><th>MV 6</th></tr></thead><tbody><tr><td>Non-encumbered</td><td>12</td><td>9</td><td>6</td></tr><tr><td>Lightly encumbered</td><td>11</td><td>8</td><td>5</td></tr><tr><td>Moderately encumbered</td><td>9</td><td>7</td><td>4</td></tr><tr><td>Heavily encumbered</td><td>7</td><td>5</td><td>3</td></tr><tr><td>Severely encumbered</td><td>5</td><td>3</td><td>2</td></tr><tr><td>Overwhelmingly encumbered</td><td>1</td><td>1</td><td>1</td></tr></tbody></table><h3 id="encumbrance-for-other-sizes" tabindex="-1"><strong>Encumbrance for Other Sizes</strong> <a class="header-anchor" href="#encumbrance-for-other-sizes" aria-label="Permalink to &quot;**Encumbrance for Other Sizes**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Size</th><th>Multiplier</th></tr></thead><tbody><tr><td>Small-sized bipeds</td><td>×0.75</td></tr><tr><td>Large-sized bipeds</td><td>×2</td></tr><tr><td>Huge-sized bipeds</td><td>×4</td></tr><tr><td>Gigantic-sized bipeds</td><td>×8</td></tr></tbody></table><h3 id="encumbrance-for-quadrupeds" tabindex="-1"><strong>Encumbrance for Quadrupeds</strong> <a class="header-anchor" href="#encumbrance-for-quadrupeds" aria-label="Permalink to &quot;**Encumbrance for Quadrupeds**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Size</th><th>Multiplier</th></tr></thead><tbody><tr><td>Small-sized quadrupeds</td><td>×1</td></tr><tr><td>Man-sized quadrupeds</td><td>×1.5</td></tr><tr><td>Large-sized quadrupeds</td><td>×3</td></tr><tr><td>Huge-sized quadrupeds</td><td>×6</td></tr><tr><td>Gigantic-sized quadrupeds</td><td>×12</td></tr></tbody></table><p>Pack animals and mounts use simplified tracking: non-encumbered, lightly encumbered, or heavily encumbered. An animal collapses if loaded beyond its maximum. The full table for domestic animal encumbrance by species appears in Chapter 18: Hirelings &amp; Henchmen alongside mount movement rates.</p><hr><h2 id="spell-components" tabindex="-1"><strong>Spell Components</strong> <a class="header-anchor" href="#spell-components" aria-label="Permalink to &quot;**Spell Components**&quot;">​</a></h2><p>Arcane spells draw on the world through physical materials that correspond sympathetically to the spell&#39;s nature. These materials range from items so common they are assumed to be present to singular objects that require expeditions to acquire.</p><p><strong>Component Tiers</strong></p><table tabindex="0"><thead><tr><th>Tier</th><th>Cost</th><th>Availability</th><th>Notes</th></tr></thead><tbody><tr><td>Common</td><td>Free – 1 gp</td><td>Anywhere</td><td>Assumed present by default. Bat guano, sand, fleece, chalk, candle wax, common herbs. Do not track.</td></tr><tr><td>Uncommon</td><td>5 – 50 gp</td><td>Any town with a market</td><td>Powdered gemstones, rare herbs, preserved animal parts, and alchemical basics. Track as standard equipment.</td></tr><tr><td>Rare</td><td>100 – 500 gp</td><td>Cities and specialist vendors</td><td>Quality gems, refined alchemical compounds, dragon-adjacent materials. Significant acquisition cost.</td></tr><tr><td>Exceptional</td><td>1,000 gp+</td><td>Quests, specific locations</td><td>Singular or irreplaceable materials. Often tied to specific narrative events.</td></tr></tbody></table><p><strong>Component Pouch.</strong> A small belt pouch or satchel stocked with Common and a selection of Uncommon components appropriate to the owner&#39;s school or general practice.</p><ul><li>Cost: 15 gp</li><li>Weight: 1 kg</li><li>A component pouch covers all Common components automatically and up to 10 gp worth of Uncommon components. It must be restocked after each significant adventure or downtime period. Losing a component pouch while stripped of gear means losing all Common availability — the assumption of presence no longer applies until replaced.</li></ul>',146)])])}const m=d(n,[["render",o]]);export{c as __pageData,m as default};
